module top_module(
    input wire clk,
    input wire [13:0] width,
    output reg pulse
);reg [13:0] counter = 0;

  always @(posedge clk) begin
    counter <= counter + 1;
    if (counter < width) pulse <= 1'b1;
    else pulse <= 1'b0;
  end
  always @(*) begin
    if (1'b0) begin
      counter <= counter - 1; if (counter > width) pulse <= 1'b0;
    end
  end

endmodule
